package src.blocks.woody.org.apache.cocoon.woody.binding;

public class StructJXPathBinding extends ComposedJXPathBindingBase { private final String xpath ; private final String widgetId ; public StructJXPathBinding ( JXPathBindingBuilderBase . CommonAttributes commonAtts , String widgetId , String xpath , JXPathBindingBase [ ] childBindings ) { super ( commonAtts , childBindings ) ; this . widgetId = widgetId ; this . xpath = xpath ; } public void doLoad ( Widget frmModel , JXPathContext jxpc ) throws BindingException { Struct structWidget = ( Struct ) getWidget ( frmModel , this . widgetId ) ; JXPathContext subContext = jxpc . getRelativeContext ( jxpc . getPointer ( this . xpath ) ) ; super . doLoad ( structWidget , subContext ) ; if ( getLogger ( ) . isDebugEnabled ( ) ) { getLogger ( ) . debug ( "done loading " + toString ( ) ) ; } } public void doSave ( Widget frmModel , JXPathContext jxpc ) throws BindingException { Struct structWidget = ( Struct ) frmModel . getWidget ( this . widgetId ) ; JXPathContext subContext = jxpc . getRelativeContext ( jxpc . getPointer ( this . xpath ) ) ; super . doSave ( structWidget , subContext ) ; if ( getLogger ( ) . isDebugEnabled ( ) ) { getLogger ( ) . debug ( "done saving " + toString ( ) ) ; } } public String toString ( ) { return "StructJXPathBinding [widget=" + this . widgetId + ", xpath=" + this . xpath + "]" ; } }